/**
 * Generate infrastructure.md content from extracted service infrastructure.
 */
export function formatInfrastructure(infra) {
    const lines = [];
    lines.push(`# Infrastructure — ${infra.serviceName}`, "");
    // Summary block
    const summaryParts = buildSummary(infra);
    if (summaryParts.length > 0) {
        for (const part of summaryParts) {
            lines.push(`> ${part}`);
        }
        lines.push("");
    }
    // Components
    if (infra.components.length > 0) {
        lines.push("## Components", "");
        for (const comp of infra.components) {
            const typeParts = [comp.deploymentType];
            if (comp.isPublicFacing)
                typeParts.push("public");
            if (comp.compute?.cpu)
                typeParts.push(`${comp.compute.cpu} CPU`);
            if (comp.compute?.memory)
                typeParts.push(`${comp.compute.memory} MB`);
            lines.push(`- **${comp.label}** — ${typeParts.join(", ")}`);
        }
        lines.push("");
    }
    // Environment Variables
    if (infra.envVars.length > 0) {
        lines.push("## Environment Variables", "");
        lines.push("| Name | Value | Source |");
        lines.push("|------|-------|--------|");
        for (const ev of infra.envVars) {
            lines.push(`| \`${ev.name}\` | \`${escapeTable(ev.value)}\` | ${ev.source} |`);
        }
        lines.push("");
    }
    // Secrets
    if (infra.secrets.length > 0) {
        lines.push("## Secrets (SSM Parameter Store)", "");
        lines.push("| Name | SSM Path |");
        lines.push("|------|----------|");
        for (const sec of infra.secrets) {
            lines.push(`| \`${sec.name}\` | \`${escapeTable(sec.arnPattern)}\` |`);
        }
        lines.push("");
    }
    // DNS
    if (infra.dns.hostnames.length > 0) {
        lines.push("## DNS", "");
        lines.push(`**Public-facing:** ${infra.dns.isPublicFacing ? "Yes" : "No"}`, "");
        for (const hostname of infra.dns.hostnames) {
            lines.push(`- \`${hostname}\``);
        }
        lines.push("");
    }
    // Dependencies
    if (infra.dependencies.length > 0) {
        lines.push("## Dependencies", "");
        for (const dep of infra.dependencies) {
            lines.push(`- ${dep}`);
        }
        lines.push("");
    }
    // IAM Permissions
    if (infra.iamPermissions.length > 0) {
        lines.push("## IAM Permissions", "");
        for (const perm of infra.iamPermissions) {
            lines.push(`- \`${perm}\``);
        }
        lines.push("");
    }
    // Observability
    if (infra.observability.logGroup || infra.observability.alarms.length > 0) {
        lines.push("## Observability", "");
        if (infra.observability.logGroup) {
            lines.push(`- **Log group:** \`${infra.observability.logGroup}\``);
        }
        for (const alarm of infra.observability.alarms) {
            lines.push(`- **Alarm:** ${alarm}`);
        }
        lines.push("");
    }
    // Environments
    const envNames = Object.keys(infra.environments);
    if (envNames.length > 0) {
        lines.push("## Environments", "");
        for (const envName of envNames) {
            const env = infra.environments[envName];
            lines.push(`### ${envName}`, "");
            if (env.enabled !== undefined) {
                lines.push(`**Enabled:** ${env.enabled ? "Yes" : "No"}`, "");
            }
            const vars = Object.entries(env.variables);
            if (vars.length > 0) {
                lines.push("| Variable | Value |");
                lines.push("|----------|-------|");
                for (const [key, value] of vars) {
                    lines.push(`| \`${key}\` | \`${escapeTable(value)}\` |`);
                }
                lines.push("");
            }
        }
    }
    // Footer
    lines.push("---");
    lines.push(`_Source: ${infra.sourceFiles.join(", ")}_`);
    lines.push("_Generated by boocontext-terraform-plugin_");
    lines.push("");
    return lines.join("\n");
}
function buildSummary(infra) {
    const parts = [];
    if (infra.components.length > 0) {
        const primary = infra.components[0];
        const runtimeParts = [primary.deploymentType];
        if (primary.moduleSource)
            runtimeParts.push(`\`${primary.moduleSource}\``);
        if (primary.compute?.cpu && primary.compute?.memory) {
            runtimeParts.push(`${primary.compute.cpu} CPU / ${primary.compute.memory} MB`);
        }
        parts.push(`**Runtime:** ${runtimeParts.join(" | ")}`);
        if (primary.enableFlag) {
            parts.push(`**Enable flag:** \`${primary.enableFlag}\``);
        }
    }
    if (infra.dns.isPublicFacing) {
        const host = infra.dns.hostnames[0];
        parts.push(`**Public-facing:** Yes${host ? ` — \`${host}\`` : ""}`);
    }
    else {
        parts.push("**Public-facing:** No (internal service)");
    }
    return parts;
}
function escapeTable(value) {
    return value.replace(/\|/g, "\\|").replace(/\n/g, " ");
}
